import spoon.reflect.CtModel;
import spoon.reflect.code.*;
import spoon.reflect.declaration.CtMethod;
import spoon.reflect.declaration.CtType;
import spoon.reflect.reference.CtExecutableReference;
import spoon.reflect.visitor.filter.TypeFilter;

import java.util.List;

/**
 * Generic Spoon transformation to fix Reflections API breaking changes.
 * Specifically fixes calls to FilterBuilder.apply() which was removed in reflections 0.10.2
 */
public class Main {
    public static void main(String[] args) {
        if (args.length < 1) {
            System.err.println("Usage: java -jar spoon-transformer.jar <source_directory>");
            System.exit(1);
        }

        String sourceDirectory = args[0];

        Launcher launcher = new Launcher();
        launcher.addInputResource(sourceDirectory);
        launcher.setSourceOutputDirectory(sourceDirectory + "-transformed");
        launcher.getEnvironment().setComplianceLevel(8);

        CtModel model = launcher.buildModel();

        // Find all FilterBuilder.apply() invocations
        List<CtInvocation> filterBuilderApplyCalls = model.getElements(new TypeFilter<>(CtInvocation.class) {
            @Override
            public boolean matches(CtInvocation element) {
                if (element.getExecutable() == null) return false;

                // Check if it's a call to FilterBuilder.apply()
                return element.getExecutable().getSimpleName().equals("apply") &&
                       element.getExecutable().getDeclaringType() != null &&
                       element.getExecutable().getDeclaringType().getQualifiedName().contains("FilterBuilder");
            }
        });

        // Replace FilterBuilder.apply() calls with correct API
        for (CtInvocation applyCall : filterBuilderApplyCalls) {
            // Get the FilterBuilder instance (target)
            CtExpression target = applyCall.getTarget();

            // Get the argument to apply()
            if (applyCall.getArguments().size() > 0) {
                CtExpression argument = applyCall.getArguments().get(0);

                // Replace: filterBuilder.apply("pattern")
                // With: filterBuilder.include("pattern").test("input")

                // Create a new invocation: filterBuilder.include("pattern").test("input")
                // For this to work properly, we need to find the context where this is used

                // This is a simple replacement - we'll replace the entire expression
                // to use the correct API pattern

                // Get the method where this invocation occurs
                CtMethod method = applyCall.getParent(CtMethod.class);
                if (method != null) {
                    // For the gauge-java case, we need to change:
                    // new FilterBuilder().include(regex).apply(s) 
                    // to:
                    // new FilterBuilder().include(regex).test(s)

                    // Create a new expression: target.include(argument).test(argument)
                    CtInvocation includeCall = target.clone();
                    if (includeCall instanceof CtInvocation) {
                        // Set the method to "include" instead of "apply"
                        CtExecutableReference<?> includeRef = includeCall.getExecutable().clone();
                        includeRef.setSimpleName("include");
                        includeCall.setExecutable(includeRef);

                        // Set the argument for include
                        includeCall.setArguments(argument.clone());

                        // Create the .test() call
                        CtInvocation testCall = launcher.getFactory().createInvocation();
                        testCall.setTarget(includeCall);
                        testCall.setExecutable(launcher.getFactory().createExecutableReference()
                                .setSimpleName("test")
                                .setDeclaringType(launcher.getFactory().createReference("org.reflections.util.FilterBuilder")));
                        testCall.setArguments(argument.clone());

                        // Replace the old call with the new one
                        applyCall.replace(testCall);
                    }
                }
            }
        }

        System.out.println("Transformation completed. Check the transformed code in " + sourceDirectory + "-transformed");
        launcher.process();
    }
}

